#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int dfs(int** graph, int n, int* visited, int node) {
    if (visited[node] == 1) return 0;
    if (visited[node] == 2) return visited[node];
    visited[node] = 1;
    int max_len = 0;
    for (int i = 0; i < n; i++) {
        if (graph[node][i] == 1) {
            max_len = max(max_len, dfs(graph, n, visited, i));
        }
    }
    visited[node] = max_len + 1;
    return visited[node];
}
int longestPath(int** graph, int n) {
    int* visited = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) visited[i] = 0;
    int max_len = 0;
    for (int i = 0; i < n; i++) {
        max_len = max(max_len, dfs(graph, n, visited, i));
    }
    free(visited);
    return max_len;
}
int main() {
    int n;
    scanf("%d", &n);
    int** graph = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        graph[i] = (int*)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            scanf("%d", &graph[i][j]);
        }
    }
    printf("%d\n", longestPath(graph, n));
    for (int i = 0; i < n; i++) free(graph[i]);
    free(graph);
    return 0;
}

